class _SAM_KVType:
    NONE=0; STRING=1; INT32=2; FLOAT32=3; POINTER=4; WIDESTRING=5; COLOR=6; UINT64=7; END=8

class _SAM_KeyValue:
    def __init__(self):
        self.name="<root>"; self.type=_SAM_KVType.NONE; self.value=None
        self.valid=False; self.children=None
    def __getitem__(self, k):
        if not self.children: return _SAM_INVALID_KV
        for c in self.children:
            if c.name.lower()==k.lower(): return c
        return _SAM_INVALID_KV
    def as_string(self, d=""): return str(self.value) if self.valid and self.value is not None else d
    def as_int(self, d=0):
        if not self.valid: return d
        if self.type in (_SAM_KVType.STRING,_SAM_KVType.WIDESTRING):
            try: return int(self.value)
            except: return d
        if self.type==_SAM_KVType.INT32: return self.value
        if self.type==_SAM_KVType.FLOAT32: return int(self.value)
        if self.type==_SAM_KVType.UINT64: return self.value & 0xFFFFFFFF
        return d
    def as_bool(self, d=False):
        if not self.valid: return d
        if self.type in (_SAM_KVType.STRING,_SAM_KVType.WIDESTRING):
            try: return int(self.value)!=0
            except: return d
        if self.type==_SAM_KVType.INT32: return self.value!=0
        if self.type==_SAM_KVType.FLOAT32: return int(self.value)!=0
        if self.type==_SAM_KVType.UINT64: return self.value!=0
        return d
    @staticmethod
    def load(path):
        import struct as _s_s
        if not os.path.exists(path): return None
        try:
            with open(path,'rb') as f: data=f.read()
            kv=_SAM_KeyValue(); pos=[0]
            if kv._rb(data,pos): return kv
        except: pass
        return None
    def _rb(self, data, pos):
        self.children=[]
        import struct as _s_s
        try:
            while pos[0]<len(data):
                t=data[pos[0]]; pos[0]+=1
                if t==_SAM_KVType.END: break
                kv=_SAM_KeyValue(); kv.type=t
                kv.name=self._rs(data,pos)
                if t==_SAM_KVType.NONE:
                    if not kv._rb(data,pos): return False
                elif t==_SAM_KVType.STRING:
                    kv.valid=True; kv.value=self._rs(data,pos)
                elif t==_SAM_KVType.INT32:
                    kv.valid=True; kv.value=_s_s.unpack_from('<i',data,pos[0])[0]; pos[0]+=4
                elif t==_SAM_KVType.UINT64:
                    kv.valid=True; kv.value=_s_s.unpack_from('<Q',data,pos[0])[0]; pos[0]+=8
                elif t==_SAM_KVType.FLOAT32:
                    kv.valid=True; kv.value=_s_s.unpack_from('<f',data,pos[0])[0]; pos[0]+=4
                elif t in (_SAM_KVType.COLOR,_SAM_KVType.POINTER):
                    kv.valid=True; kv.value=_s_s.unpack_from('<I',data,pos[0])[0]; pos[0]+=4
                else: raise ValueError
                if pos[0]>len(data): raise ValueError
                self.children.append(kv)
            self.valid=True; return True
        except: return False
    @staticmethod
    def _rs(data, pos):
        e=pos[0]
        while e<len(data) and data[e]!=0: e+=1
        s=data[pos[0]:e].decode('utf-8',errors='replace')
        pos[0]=e+1; return s

_SAM_INVALID_KV = _SAM_KeyValue()

def _sam_get_localized(kv, lang, default):
    n = kv[lang].as_string("")
    if n: return n
    if lang != "english":
        n = kv["english"].as_string("")
        if n: return n
    n = kv.as_string("")
    return n if n else default

def _sam_load_schema(app_id, lang):
    sp = _sam_get_steam_path()
    if not sp: return ([], [])
    fn = f"UserGameStatsSchema_{app_id}.bin"
    p = os.path.join(sp, "appcache", "stats", fn)
    if not os.path.exists(p): return ([], [])
    kv = _SAM_KeyValue.load(p)
    if kv is None: return ([], [])
    ach_defs = []; stat_defs = []
    stats = kv[str(app_id)]["stats"]
    if not stats.valid or not stats.children: return ([], [])
    for st in stats.children:
        if not st.valid: continue
        tn = st["type"]
        if tn.valid and tn.type==_SAM_KVType.STRING:
            ts = tn.as_string("").lower()
            tm = {'integer':0,'float':1,'averagerate':2,'achievements':3,'groupachievements':4}
            stype = tm.get(ts, -1)
        else:
            stype = -1
        if stype == -1:
            tin = st["type_int"]
            stype = tin.as_int(0) if tin.valid else tn.as_int(0)
        if stype == 0:
            sid = st["name"].as_string("")
            nm = _sam_get_localized(st["display"]["name"], lang, sid)
            stat_defs.append({'id':sid,'display_name':nm,'type':'int','min':st["min"].as_int(None),'max':st["max"].as_int(None),'default':st["default"].as_int(0),'permission':st["permission"].as_int(0)})
        elif stype in (1,2):
            sid = st["name"].as_string("")
            nm = _sam_get_localized(st["display"]["name"], lang, sid)
            stat_defs.append({'id':sid,'display_name':nm,'type':'float','min':st["min"].as_float(None),'max':st["max"].as_float(None),'default':st["default"].as_float(0.0),'permission':st["permission"].as_int(0)})
        elif stype in (3,4):
            if not st.children: continue
            for bits in st.children:
                if bits.name.lower()!="bits" or not bits.valid or not bits.children: continue
                for bit in bits.children:
                    aid=bit["name"].as_string("")
                    anm=_sam_get_localized(bit["display"]["name"],lang,aid)
                    adesc=_sam_get_localized(bit["display"]["desc"],lang,"")
                    d=_SAM_AchievementDef()
                    d.id=aid; d.name=anm; d.description=adesc
                    d.icon_normal=bit["display"]["icon"].as_string("")
                    d.icon_locked=bit["display"]["icon_gray"].as_string("")
                    d.is_hidden=bit["display"]["hidden"].as_bool(False)
                    d.permission=bit["permission"].as_int(0)
                    ach_defs.append(d)
    return (ach_defs, stat_defs)

def _sam_scan_games():
    sp = _sam_get_steam_path()
    if not sp: return []
    lf = os.path.join(sp, "steamapps", "libraryfolders.vdf")
    if not os.path.exists(lf): return []
    try:
        with open(lf, 'r', encoding='utf-8', errors='replace') as f: txt = f.read()
    except: return []
    lib_paths = []
    for m in re.finditer(r'"path"\s*"([^"]+)"', txt):
        lib_paths.append(m.group(1))
    if not lib_paths:
        lib_paths = [os.path.join(sp, "steamapps")]
    games = []
    for lp in lib_paths:
        sa = os.path.join(lp, "steamapps")
        if not os.path.isdir(sa): continue
        for fn in os.listdir(sa):
            if not fn.startswith("appmanifest_") or not fn.endswith(".acf"): continue
            fp = os.path.join(sa, fn)
            try:
                with open(fp, 'r', encoding='utf-8', errors='replace') as f: acf = f.read()
            except: continue
            aid = re.search(r'"appid"\s*"(\d+)"', acf)
            name = re.search(r'"name"\s*"([^"]*)"', acf)
            if aid:
                games.append({'app_id': int(aid.group(1)), 'name': name.group(1) if name else 'Unknown'})
    games.sort(key=lambda x: x['name'].lower())
    return games

