    # ---- Translation helper for custom buttons ----
    def _tr(steam_app, key):
        lang = steam_app.settings.get('language', 'tr')
        return extra_text.get(lang, {}).get(key, extra_text.get('en', {}).get(key, steam_app.tr(key)))

    # ---- SAM: Game Picker (installed + library scan) ----
    def _open_game_picker(self):
        import subprocess as _sp
        _sam_dir = Path(os.environ.get('APPDATA', str(Path.home()))) / "SteamToolsLua" / "SAM"
        _sam_dir.mkdir(parents=True, exist_ok=True)
        _picker_exe = _sam_dir / "SAM.Picker.exe"
        _game_exe = _sam_dir / "SAM.Game.exe"
        if _picker_exe.exists() and _game_exe.exists():
            _sp.Popen([str(_picker_exe)])
            return
        _dlg = tk.Toplevel(self.root)
        _dlg.title("SAM")
        _dlg.geometry("300x80")
        _dlg.configure(bg='#08080e')
        _dlg.transient(self.root)
        _dlg.grab_set()
        _dlg.resizable(False, False)
        tk.Label(_dlg, text="SAM.Picker.exe indiriliyor...", fg='#f6ad55', bg='#08080e', font=('Segoe UI', 10)).pack(expand=True)
        _dlg.update()
        _base = 'https://raw.githubusercontent.com/tttaaahhhaaa/SteamToolsLua/main'
        _ok = True
        for _name in ('SAM.Picker.exe', 'SAM.Game.exe'):
            _dst = _sam_dir / _name
            try:
                import requests as _req
                _r = _req.get(f'{_base}/{_name}', timeout=30)
                if _r.status_code == 200:
                    _dst.write_bytes(_r.content)
                else:
                    _ok = False
            except:
                _ok = False
        _dlg.destroy()
        if _ok:
            _sp.Popen([str(_picker_exe)])
        else:
            import ctypes as _ct
            _ct.windll.user32.MessageBoxW(0, "SAM.Picker.exe indirilemedi.", "Hata", 0x10)

    # ---- SAM: Achievement Manager (Steam API direct, no .bin dependency) ----
    def _open_achievement_manager(self, app_id, game_name_hint):
        import threading as _sam_thr
        import time as _sam_time
        _top = tk.Toplevel(self.root)
        _top.title(f"Basarim Yoneticisi - {game_name_hint} ({app_id})")
        _top.geometry("900x650")
        _top.configure(bg='#08080e')
        _top.minsize(700, 450)
        _top.transient(self.root)
        _top.grab_set()
        _status_var = tk.StringVar(value="Steam'a baglaniyor...")
        _status_label = tk.Label(_top, textvariable=_status_var, fg='#f6ad55', bg='#08080e', font=('Segoe UI', 10))
        _status_label.pack(fill=tk.X, padx=16, pady=(8, 0))
        _header = tk.Label(_top, text=f"{game_name_hint} [{app_id}]", font=('Bahnschrift SemiBold', 18), fg='#e0e0f0', bg='#08080e')
        _header.pack(fill=tk.X, padx=16, pady=(10, 2))
        _prog_frame = tk.Frame(_top, bg='#08080e')
        _prog_frame.pack(fill=tk.X, padx=16, pady=(2, 4))
        _prog_var = tk.IntVar(value=0)
        _prog_label = tk.Label(_prog_frame, text="0/0", fg='#48bb78', bg='#08080e', font=('Segoe UI', 10))
        _prog_label.pack(side=tk.LEFT, padx=(0, 8))
        _prog_bar = tk.Canvas(_prog_frame, height=8, bg='#1a1a2e', highlightthickness=0, bd=0)
        _prog_bar.pack(side=tk.LEFT, fill=tk.X, expand=True)
        _frame = tk.Frame(_top, bg='#0d1724')
        _frame.pack(fill=tk.BOTH, expand=True, padx=16, pady=4)
        _scroll = tk.Scrollbar(_frame, orient=tk.VERTICAL, bg='#12122a', activebackground='#2a2a5a')
        _canvas = tk.Canvas(_frame, bg='#0d1724', highlightthickness=0, yscrollcommand=_scroll.set)
        _scroll.config(command=_canvas.yview)
        _scroll.pack(side=tk.RIGHT, fill=tk.Y)
        _canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        _inner = tk.Frame(_canvas, bg='#0d1724')
        _canvas.create_window((0, 0), window=_inner, anchor='nw', tags='inner')
        def _config_inner(_e=None):
            _canvas.configure(scrollregion=_canvas.bbox('all'))
            _canvas.itemconfig('inner', width=_canvas.winfo_width())
        _inner.bind('<Configure>', _config_inner)
        def _on_mw(e):
            _canvas.yview_scroll(int(-1 * (e.delta / 120)), "units")
        _canvas.bind("<MouseWheel>", _on_mw)
        _canvas.bind("<Button-4>", lambda e: _canvas.yview_scroll(-1, "units"))
        _canvas.bind("<Button-5>", lambda e: _canvas.yview_scroll(1, "units"))
        _btn_frame = tk.Frame(_top, bg='#08080e')
        _btn_frame.pack(fill=tk.X, padx=16, pady=(4, 12))
        _vars = []
        _ach_items = []
        _client_ref = [None]
        def _draw_prog(done, total):
            _prog_label.config(text=f"{done}/{total}")
            _prog_bar.delete('all')
            if total > 0:
                w = _prog_bar.winfo_width() or 200
                fw = max(2, int(w * done / total))
                _prog_bar.create_rectangle(0, 0, fw, 8, fill='#48bb78', outline='')
        _vars.clear()
        for _ch in list(_inner.winfo_children()): _ch.destroy()
        _status_var.set("Steam'e baglaniyor...")
        _top.update_idletasks()
        def _load_data():
            try:
                _c = _SAM_SteamClient()
                _c.initialize(app_id)
                _c.run_callbacks()
                _sid = _c.user.get_steam_id()
                if _sid:
                    _c.stats.request_user_stats(_sid)
                    for _ in range(6):
                        _sam_time.sleep(0.5)
                        _c.run_callbacks()
                        if _c.stats.get_num_achievements() > 0: break
                lang = self.settings.get('language', 'tr')
                _lang_map = {'tr':'turkish','en':'english','es':'spanish','fr':'french','de':'german','ja':'japanese'}
                _s_lang = _lang_map.get(lang, 'english')
                _num = _c.stats.get_num_achievements()
                _names = []
                if _num > 0:
                    for _i in range(_num):
                        _n = _c.stats.get_achievement_name(_i)
                        if _n:
                            _names.append({'id': _n, 'name': _n, 'desc': ''})
                _defs, _ = _sam_load_schema(app_id, _s_lang)
                if _defs:
                    _def_map = {}
                    for _d in _defs:
                        _def_map[_d.id] = _d
                    for _ni in _names:
                        _d = _def_map.get(_ni['id'])
                        if _d:
                            _ni['name'] = _d.name
                            _ni['desc'] = _d.description
                    for _d in _defs:
                        if not any(n['id'] == _d.id for n in _names):
                            _names.append({'id': _d.id, 'name': _d.name, 'desc': _d.description})
                _unlocked = 0
                _states = []
                for _ni in _names:
                    ok, ach = _c.stats.get_achievement(_ni['id'])
                    _is_unlocked = bool(ok and ach)
                    if _is_unlocked: _unlocked += 1
                    _states.append(_is_unlocked)
                return (_c, _names, _states, _unlocked)
            except Exception as _e:
                return _e
        def _on_data(data):
            if isinstance(data, Exception):
                _status_var.set(f"Hata: {data}")
                return
            _c, _names, _states, _unlocked = data
            _client_ref[0] = _c
            _ach_items[:] = _names
            for _idx, _ni in enumerate(_names):
                _f = tk.Frame(_inner, bg='#0d1724')
                _f.pack(fill=tk.X, padx=6, pady=2)
                _var = tk.BooleanVar(value=_states[_idx])
                _vars.append(_var)
                _txt = f"[ACIK] {_ni['name']}" if _states[_idx] else f"[KAPALI] {_ni['name']}"
                if _ni['desc']:
                    _txt += f" - {_ni['desc']}"
                _cb = tk.Checkbutton(_f, variable=_var, bg='#0d1724', fg='#e0e0f0', selectcolor='#1a1a2e', activebackground='#0d1724', activeforeground='#e0e0f0', font=('Segoe UI', 9), anchor='w', wraplength=700, justify=tk.LEFT)
                _cb.pack(side=tk.LEFT, fill=tk.X, expand=True)
                _cb.config(text=_txt)
            _draw_prog(_unlocked, len(_names))
            _status_var.set(f"{len(_names)} basarim ({_unlocked}/{len(_names)} acik).")
        def _load():
            data = _load_data()
            _top.after(0, lambda: _on_data(data))
        _sam_thr.Thread(target=_load, daemon=True).start()
        _sam_thr.Thread(target=_load, daemon=True).start()
        def _refresh():
            _status_var.set("Yenileniyor...")
            _sam_thr.Thread(target=_load, daemon=True).start()
        def _unlock_sel():
            _c = _client_ref[0]
            if not _c or not _c.stats: return
            for i, _v in enumerate(_vars):
                if _v.get() and i < len(_ach_items):
                    try: _c.stats.set_achievement(_ach_items[i]['id'])
                    except: pass
            _c.run_callbacks()
            _status_var.set("Secilenler isaretlendi. Kaydet butonuna basin.")
        def _lock_sel():
            _c = _client_ref[0]
            if not _c or not _c.stats: return
            for i, _v in enumerate(_vars):
                if _v.get() and i < len(_ach_items):
                    try: _c.stats.clear_achievement(_ach_items[i]['id'])
                    except: pass
            _c.run_callbacks()
            _status_var.set("Secilenler isaretlendi. Kaydet butonuna basin.")
        def _save():
            _c = _client_ref[0]
            if not _c or not _c.stats: return
            _old_aid = os.environ.get('SteamAppId')
            os.environ['SteamAppId'] = str(app_id)
            try:
                _c.run_callbacks()
                _result = False
                for _attempt in range(3):
                    if _c.stats.store_stats():
                        _result = True
                        break
                    _sam_time.sleep(0.3)
                    _c.run_callbacks()
                if _result:
                    _status_var.set("Kaydedildi!")
                    _sam_time.sleep(0.5)
                    _sam_thr.Thread(target=_load, daemon=True).start()
                else:
                    _status_var.set("Kaydetme basarisiz! Steam baglantinizi kontrol edin.")
            except Exception as _e:
                _status_var.set(f"Kayit hatasi: {_e}")
            finally:
                if _old_aid: os.environ['SteamAppId'] = _old_aid
        def _reset_all():
            _c = _client_ref[0]
            if not _c or not _c.stats: return
            if not tk.messagebox.askyesno("Reset All", "Tum basarimlari ve istatistikleri sifirla?"):
                return
            try:
                if _c.stats.reset_all(True):
                    _status_var.set("Sifirlandi!")
                    _c.run_callbacks()
                    _sam_time.sleep(0.5)
                    _sam_thr.Thread(target=_load, daemon=True).start()
                else:
                    _status_var.set("Sifirlama basarisiz!")
            except Exception as _e:
                _status_var.set(f"Sifirlama hatasi: {_e}")
        _btn_style = {'fg':'#e0e0f0','font':('Segoe UI Semibold',10),'bd':0,'padx':10,'pady':4,'cursor':'hand2'}
        def _select_all():
            for _v in _vars: _v.set(True)
        def _unselect_all():
            for _v in _vars: _v.set(False)
        def _go_back():
            _top.destroy()
        tk.Button(_btn_frame, text="Geri", command=_go_back, bg='#3a3a1a', activebackground='#5a5a2a', **_btn_style).pack(side=tk.LEFT, padx=(0, 4))
        tk.Button(_btn_frame, text="Hepsini Sec", command=_select_all, bg='#244363', activebackground='#315f8e', **_btn_style).pack(side=tk.LEFT, padx=(0,4))
        tk.Button(_btn_frame, text="Hepsini Kaldir", command=_unselect_all, bg='#3a1a1a', activebackground='#5a2a2a', **_btn_style).pack(side=tk.LEFT, padx=(0,4))
        tk.Button(_btn_frame, text="Secileni Ac", command=_unlock_sel, bg='#2d4a3e', activebackground='#3d6b56', **_btn_style).pack(side=tk.LEFT, padx=(0,4))
        tk.Button(_btn_frame, text="Secileni Kitle", command=_lock_sel, bg='#3a1a1a', activebackground='#5a2a2a', **_btn_style).pack(side=tk.LEFT, padx=(0,4))
        tk.Button(_btn_frame, text="Kaydet", command=_save, bg='#244363', activebackground='#315f8e', **_btn_style).pack(side=tk.LEFT, padx=(0,4))
        tk.Button(_btn_frame, text="Yenile", command=_refresh, bg='#244363', activebackground='#315f8e', **_btn_style).pack(side=tk.LEFT, padx=(0,4))
        tk.Button(_btn_frame, text="Tumunu Sifirla", command=_reset_all, bg='#3a1a1a', activebackground='#5a2a2a', **_btn_style).pack(side=tk.LEFT, padx=(0,4))
        tk.Button(_btn_frame, text="Kapat", command=_top.destroy, bg='#3a1a1a', activebackground='#5a2a2a', **_btn_style).pack(side=tk.RIGHT)

    SteamApp._open_game_picker = _open_game_picker
    SteamApp._open_achievement_manager = _open_achievement_manager

    # ---- Download recall ----
    _data_dir = Path(os.environ.get('APPDATA', str(Path.home()))) / "SteamToolsLua"
    try: _data_dir.mkdir(parents=True, exist_ok=True)
    except: pass
    _recall_path = _data_dir / "downloaded_games.ini"
    # auto-migrate old ini files from app dir
    _old_dir = Path(__file__).resolve().parent
    for _dl_name in ('downloaded_games.ini',):
        _dl_old = _old_dir / _dl_name
        _dl_new = _data_dir / _dl_name
        if _dl_old.exists() and not _dl_new.exists():
            try: os.replace(str(_dl_old), str(_dl_new))
            except: pass
        elif _dl_old.exists():
            try: _dl_old.unlink()
            except: pass
    def _save_dl_name(name):
        if not name: return
        try:
            _r = _configparser.ConfigParser()
            _r.optionxform = str
            if _recall_path.exists():
                try: _r.read(str(_recall_path), encoding='utf-8')
                except: pass
            if 'Games' not in _r: _r['Games'] = {}
            _r['Games'][name.strip()] = _time.strftime('%Y-%m-%d %H:%M')
            with open(str(_recall_path), 'w', encoding='utf-8') as _f: _r.write(_f)
        except: pass

