    # ---- polished_reflow_cards ----
    def polished_reflow_cards(self):
        if not self.cards:
            return
        width = max(self.results_canvas.winfo_width(), 820)
        try:
            cw = max(404, min(int(self.settings.get('card_width', card_width)), 520))
        except Exception:
            cw = card_width
        columns = max(1, (width + 28) // (cw + 28))
        for idx, card in enumerate(self.cards):
            row = idx // columns
            col = idx % columns
            card.grid(row=row, column=col, padx=14, pady=14, sticky='nsew')
        for col in range(columns):
            self.cards_frame.grid_columnconfigure(col, weight=1, uniform='card_col')
        self.results_canvas.configure(scrollregion=self.results_canvas.bbox('all'))

    # ---- placeholder_image ----
    def placeholder_image(self, title):
        canvas = Image.new('RGB', cover_size, '#16273a')
        draw = ImageDraw.Draw(canvas)
        draw.rectangle([(0, 0), (cover_size[0], cover_size[1])], fill='#0f1b2a')
        draw.rectangle([(0, 0), (cover_size[0], 62)], fill='#19324a')
        initials = ''.join(word[0] for word in clean_title(title).split()[:2]).upper() or 'ST'
        draw.ellipse((24, 78, 114, 168), fill='#66c0f4')
        draw.text((49, 104), initials, fill='#07111c')
        draw.text((140, 90), clean_title(title)[:32], fill='#f7fafc')
        draw.text((140, 118), self.tr('placeholder.header_failed'), fill='#8ca5be')
        return canvas

    # ---- image_worker ----
    _img_ua = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'

    def image_worker(self, result):
        image_url = result.get('image_url')
        image = None
        try:
            image_h = max(150, min(int(self.settings.get('cover_height', cover_size[1])), 240))
        except Exception:
            image_h = cover_size[1]
        size = (cover_size[0], image_h)
        if image_url:
            try:
                headers = {'User-Agent': _img_ua}
                response = g['session'].get(image_url, timeout=20, headers=headers)
                response.raise_for_status()
                pil_image = Image.open(g['io'].BytesIO(response.content)).convert('RGB')
                contained = ImageOps.contain(pil_image, size, method=Image.Resampling.LANCZOS)
                image = Image.new('RGB', size, '#0d1825')
                image.paste(contained, ((size[0] - contained.width) // 2, (size[1] - contained.height) // 2))
            except Exception:
                pass
        if image is None:
            image = ImageOps.contain(self.placeholder_image(result['name']), size, method=Image.Resampling.LANCZOS)
        self.ui(self._finalize_image, result['appid'], image)

    # ---- finalize_image ----
    def finalize_image(self, appid, image):
        photo = ImageTk.PhotoImage(image)
        self.image_cache[appid] = photo
        for card in self.image_watchers.pop(appid, []):
            card.set_image(photo)

    # ---- play_notification ----
    def play_notification():
        sound = resource_path('bildirim sesi.mp3')
        if not sound.exists():
            return
        alias = 'steamtools_notice'
        winmm = ctypes.windll.winmm
        winmm.mciSendStringW('stop ' + alias, None, 0, None)
        winmm.mciSendStringW('close ' + alias, None, 0, None)
        winmm.mciSendStringW('open "' + str(sound) + '" type mpegvideo alias ' + alias, None, 0, None)
        winmm.mciSendStringW('play ' + alias + ' from 0', None, 0, None)

