    # ---- localized_rate_text ----
    def localized_rate_text(self, provider_name):
        info = self.provider_manager.rate_info.get(provider_name)
        if not info:
            return self.tr('settings.not_queried')
        if info.get('status') == 'yerel':
            return self.tr('settings.unlimited_local')
        if info.get('status') == 'yok':
            return self.tr('settings.no_limit_info')
        if info.get('status') == 'hata':
            return self.tr('settings.rate_error')
        if provider_name == 'groq':
            return self.tr('settings.requests') + ': ' + str(info.get('requests', '?')) + ' | Token: ' + str(info.get('tokens', '?'))
        if provider_name == 'openrouter':
            return self.tr('settings.remaining') + ': ' + str(info.get('remaining', '?'))
        return self.tr('settings.not_queried')

