    # ---- Status Indicator Helper ----
    def _set_indicator(self, text, state):
        try:
            if not hasattr(self, '_indicator_history'):
                self._indicator_history = []
            ts = _time.strftime('%H:%M:%S')
            self._indicator_history.append((ts, text, state))
            if len(self._indicator_history) > 50:
                self._indicator_history.pop(0)
            if hasattr(self, 'set_status'):
                self.set_status(text, state)
            else:
                colors = {'idle':'#708090','working':'#f6ad55','online':'#48bb78','offline':'#f56565'}
                labels = {'idle':'Beklemede/Idle','working':'Calisiyor/Working','online':'Aktif/Online','offline':'Hata/Error'}
                if hasattr(self, 'status_dot') and hasattr(self, 'status_oval'):
                    self.status_dot.itemconfig(self.status_oval, fill=colors.get(state, colors['idle']))
                    try:
                        self.status_dot.itemconfig(self.status_oval, tooltip=f'{labels.get(state, state)}: {text[:50]}')
                    except: pass
                if hasattr(self, 'status_var'):
                    self.status_var.set(f'{labels.get(state, state)}: {text[:60]}')
                if hasattr(self, 'status_lbl') and self.status_lbl.winfo_exists():
                    self.status_lbl.config(text='')
        except Exception:
            pass

    SteamApp._set_indicator = _set_indicator

    # ---- Headless PowerShell Runner ----
    import os as _os
    import shutil as _shutil
    import subprocess as _subprocess
    import tempfile as _tempfile
    import zipfile as _zipfile
    import configparser as _configparser
    import tkinter.messagebox as _messagebox
    import time as _time
    _batch_threading = threading

    # ---- Sound effects (disabled) ----
    def _play_sound(kind):
        pass

    def _run_headless_powershell(self, cmd, label, status_light=None):
        def _task():
            try:
                self.log(f"[{label}] başlatılıyor...")
                self._set_indicator(f"{label} {_tr(self, 'indicator.working')}", 'working')
                if status_light is not None:
                    try: status_light.config(fg='#f6ad55')
                    except: pass
                si = _subprocess.STARTUPINFO()
                si.dwFlags |= _subprocess.STARTF_USESHOWWINDOW
                result = _subprocess.run(
                    ["powershell", "-Command", cmd],
                    capture_output=True, text=True, timeout=300,
                    startupinfo=si, creationflags=0x08000000
                )
                if result.returncode == 0:
                    msg = f"{label} başarıyla tamamlandı."
                    self.log(f"[{label}] {msg}")
                    self._set_indicator(msg, 'online')
                    _play_sound('done')
                    if status_light is not None:
                        try: status_light.config(fg='#48bb78')
                        except: pass
                    # Post-install: move ltsteamplugin-main up one level
                    if 'luatools' in label.lower():
                        try:
                            _plugins = Path("C:\\Program Files (x86)\\Steam\\millennium\\plugins")
                            _luatools_dir = _plugins / "luatools"
                            if _luatools_dir.exists():
                                _subs = [d for d in _luatools_dir.iterdir() if d.is_dir()]
                                if _subs:
                                    _src = _subs[0]
                                    _dst = _plugins / _src.name
                                    if not _dst.exists():
                                        _shutil.move(str(_src), str(_dst))
                                        self.log(f"{_src.name} başarıyla plugins/ klasörüne taşındı.")
                        except Exception as e:
                            self.log(f"luatools klasör taşıma hatası: {e}")
                else:
                    err = result.stderr.strip()[:200] or "Bilinmeyen hata"
                    self.log(f"[{label}] HATA: {err}")
                    self._set_indicator(f"{label} {_tr(self, 'indicator.fail')}", 'offline')
                    _play_sound('error')
                    if status_light is not None:
                        try: status_light.config(fg='#f56565')
                        except: pass
            except _subprocess.TimeoutExpired:
                self.log(f"[{label}] zaman aşımı!")
                self._set_indicator(f"{label} {_tr(self, 'indicator.timeout')}", 'offline')
                _play_sound('error')
                if status_light is not None:
                    try: status_light.config(fg='#f56565')
                    except: pass
            except Exception as e:
                self.log(f"[{label}] HATA: {e}")
                self._set_indicator(f"{label} {_tr(self, 'indicator.err')}", 'offline')
                _play_sound('error')
                if status_light is not None:
                    try: status_light.config(fg='#f56565')
                    except: pass
        _batch_threading.Thread(target=_task, daemon=True).start()
        _play_sound('start')

    SteamApp._run_headless_powershell = _run_headless_powershell

    # ---- Batch Inject All ----
    def batch_inject_all(self):
        games_dir = _get_1ng_base()
        if not games_dir.exists():
            try:
                games_dir.mkdir(parents=True, exist_ok=True)
                self.log(f"[1 New Games] klasörü oluşturuldu: {games_dir}")
            except Exception as e:
                self.log(f"[1 New Games] klasörü oluşturulamadı: {e}")
                _messagebox.showerror(_tr(self, 'inject.err_title'), f"{_tr(self, 'inject.err_create')}\n{e}")
                return
        self.settings['new_games_folder'] = str(games_dir.resolve())
        g['save_settings'](self.settings)
        self.log(f"Taranan klasör: {games_dir}")
        self._set_indicator(_tr(self, 'indicator.scanning'), 'working')
        zips = sorted(games_dir.glob("*.zip"))
        if not zips:
            self.log(f"[{games_dir.name}] içinde .zip dosyası bulunamadı.")
            self._set_indicator(_tr(self, 'indicator.no_zips'), 'idle')
