    # ---- Online-Fix automation ----
    def _find_steam_game_path(appid):
        """Find a Steam game's install path by AppID using registry and VDF files."""
        import winreg
        try:
            key = winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE, r'SOFTWARE\WOW6432Node\Valve\Steam')
            steam_path = Path(winreg.QueryValueEx(key, 'InstallPath')[0])
            winreg.CloseKey(key)
        except:
            steam_path = Path('C:\\Program Files (x86)\\Steam')
        vdf_path = steam_path / 'steamapps' / 'libraryfolders.vdf'
        library_paths = [steam_path / 'steamapps']
        if vdf_path.exists():
            try:
                text = vdf_path.read_text('utf-8', errors='ignore')
                for m in re.finditer(r'"path"\s*"([^"]+)"', text):
                    lp = Path(m.group(1)) / 'steamapps'
                    if lp.exists():
                        library_paths.append(lp)
            except:
                pass
        for lib in library_paths:
            manifest = lib / f'appmanifest_{appid}.acf'
            if manifest.exists():
                try:
                    text = manifest.read_text('utf-8', errors='ignore')
                    m = re.search(r'"installdir"\s*"([^"]+)"', text)
                    if m:
                        install_dir = lib / 'common' / m.group(1)
                        if install_dir.exists():
                            return install_dir
                except:
                    pass
        return None

    def _parse_torrent_files(torrent_path):
        """Minimal bencode parser to extract file list from .torrent."""
        import io
        def _bdecode(data, pos=0):
            if data[pos:pos+1] == b'd':
                pos += 1
                d = {}
                while data[pos:pos+1] != b'e':
                    k, pos = _bdecode(data, pos)
                    v, pos = _bdecode(data, pos)
                    d[k] = v
                return d, pos + 1
            elif data[pos:pos+1] == b'l':
                pos += 1
                lst = []
                while data[pos:pos+1] != b'e':
                    v, pos = _bdecode(data, pos)
                    lst.append(v)
                return lst, pos + 1
            elif data[pos:pos+1] == b'i':
                end = data.index(b'e', pos)
                return int(data[pos+1:end]), end + 1
            elif data[pos:pos+1] in (b'0',b'1',b'2',b'3',b'4',b'5',b'6',b'7',b'8',b'9'):
                end = data.index(b':', pos)
                length = int(data[pos:end])
                start = end + 1
                return data[start:start+length], start + length
            else:
                raise ValueError(f'Unexpected data at {pos}: {data[pos:pos+10]}')
        with open(torrent_path, 'rb') as f:
            data = f.read()
        decoded, _ = _bdecode(data)
        info = decoded.get(b'info', {})
        files = []
        if b'files' in info:
            for fdict in info[b'files']:
                path_bytes = b'/'.join(fdict[b'path'])
                try:
                    path_str = path_bytes.decode('utf-8')
                except:
                    path_str = path_bytes.decode('latin-1')
                files.append({'path': path_str, 'length': fdict.get(b'length', 0)})
        elif b'name' in info:
            try:
                name = info[b'name'].decode('utf-8')
            except:
                name = info[b'name'].decode('latin-1')
            files.append({'path': name, 'length': info.get(b'length', 0)})
        return files

    # ---- Helper: find bundled UnRAR.exe (no WinRAR/WinRAR dep) ----
    def _get_bundled_unrar():
        _check = [str(Path(os.environ.get('APPDATA', str(Path.home()))) / 'SteamToolsLua' / 'UnRAR.exe')]
        if getattr(sys, 'frozen', False):
            _mp = getattr(sys, '_MEIPASS', None)
            if _mp:
                _check.append(str(Path(_mp) / 'UnRAR.exe'))
        _check.append(str(Path(__file__).parent / 'UnRAR.exe'))
        for _p in _check:
            if os.path.exists(_p):
                return _p
        return None
    _BUNDLED_UNRAR = _get_bundled_unrar()

    def _ensure_unrar():
        nonlocal _BUNDLED_UNRAR
        if _BUNDLED_UNRAR and os.path.exists(_BUNDLED_UNRAR):
            return _BUNDLED_UNRAR
        _target = str(Path(os.environ.get('APPDATA', str(Path.home()))) / 'SteamToolsLua' / 'UnRAR.exe')
        if os.path.exists(_target):
            _BUNDLED_UNRAR = _target
            return _target
        try:
            _r = __import__('requests').get('https://raw.githubusercontent.com/tttaaahhhaaa/SteamToolsLua/main/bypass/UnRAR.exe', timeout=15)
            if _r.status_code == 200:
                Path(_target).write_bytes(_r.content)
                _BUNDLED_UNRAR = _target
                return _target
        except: pass
        return None

    def _extract_rar_with_unrar(rar_path, out_dir, passwords, log, indicator):
        # Try 7-Zip first (much faster, multi-threaded)
        for _7z in (r'C:\Program Files\7-Zip\7z.exe', r'C:\Program Files (x86)\7-Zip\7z.exe'):
            if os.path.exists(_7z):
                for pw in passwords:
                    try:
                        cmd = [_7z, 'x', '-y', f'-p{pw}' if pw else '-p""', f'-o{out_dir}', '-mmt=on', str(rar_path)]
                        proc = subprocess.run(cmd, capture_output=True, timeout=120, creationflags=0x08000000)
                        if proc.returncode == 0:
                            log(f'[OnlineFix] 7z basarili (pw={pw})')
                            return True
                    except: pass
                break
        _unrar = _ensure_unrar()
        if not _unrar:
            log('[OnlineFix] UnRAR.exe bulunamadi, indirme de basarisiz')
            return False
        for pw in passwords:
            try:
                cmd = [_unrar, 'x', '-y', str(rar_path), f'{out_dir}\\']
                if pw: cmd.insert(2, f'-p{pw}')
                proc = subprocess.run(cmd, capture_output=True, timeout=120, creationflags=0x08000000)
                if proc.returncode == 0 or proc.returncode == 1:
                    log(f'[OnlineFix] UnRAR basarili (pw={pw})')
                    return True
            except: pass
        return False

    def _download_structured(sess, dl_urls, out_dir, appid, headers, cookies, find_func, log, indicator):
        import time as _t
        # Try Fix Repair
        upload_base = None
        for u in dl_urls:
            if '/uploads/' in u: upload_base = u; break
        if upload_base:
            repair_url = upload_base + '/Fix%20Repair/'
            log(f'[OnlineFix] Fix Repair aranıyor: {repair_url}')
            hr = sess.get(repair_url, timeout=15, headers=headers, cookies=cookies)
            if hr.status_code == 200 and 'Generic.rar' in hr.text:
                for m2 in re.finditer(r'<a href="([^"]+Generic[^"]*\.rar)"', hr.text, re.IGNORECASE):
                    rar_path = m2.group(1)
                    rar_url = rar_path if rar_path.startswith('http') else repair_url.rstrip('/') + '/' + rar_path
                    rar_name = rar_path.split('/')[-1] if '/' in rar_path else rar_path
                    dl_path = out_dir / rar_name
                    log(f'[OnlineFix] İndiriliyor: {rar_name}')
                    indicator('Online-Fix indiriliyor...', 'working')
                    rd = sess.get(rar_url, stream=True, timeout=120, headers=headers, cookies=cookies)
                    if rd.status_code != 200:
                        log(f'[OnlineFix] HTTP {rd.status_code}'); indicator('OnlineFix: HTTP hatası', 'offline')
                        return False
                    total = int(rd.headers.get('Content-Length', 0))
                    downloaded = 0; t0 = _t.time()
                    with open(str(dl_path), 'wb') as f:
                        for chunk in rd.iter_content(chunk_size=65536):
                            if chunk:
                                f.write(chunk); downloaded += len(chunk)
                                if total:
                                    pct = int(downloaded*100/total)
                                    speed = downloaded/(_t.time()-t0)/1024 if (_t.time()-t0) > 0 else 0
                                    indicator(f'OnlineFix: %{pct} ({speed:.0f} KB/s)', 'working')
                    log(f'[OnlineFix] İndirme tamam: {dl_path}')
                    # Extract directly into out_dir (flatten subfolders)
                    _passwords = ('', 'online-fix.me')
                    _pw_map = {'': 'yok', 'online-fix.me': 'online-fix.me'}
                    ok = _extract_rar_with_unrar(dl_path, out_dir, _passwords, log, indicator)
                    if ok:
                        log(f'[OnlineFix] Çıkartıldı -> {out_dir}')
                        try: dl_path.unlink(); log('[OnlineFix] .rar silindi')
                        except: pass
                        indicator('OnlineFix hazır', 'online')
                        os.startfile(str(out_dir))
                        return True
                    else:
                        log('[OnlineFix] Çıkartılamadı (UnRAR)')
                        indicator('OnlineFix: çıkartılamadı', 'offline')
                        os.startfile(str(out_dir))
                        return False
        # Try torrent
        tor_base = None
        for u in dl_urls:
            if '/torrents/' in u: tor_base = u; break
        if tor_base:
            log(f'[OnlineFix] Torrent aranıyor: {tor_base}')
            ht = sess.get(tor_base, timeout=15, headers=headers, cookies=cookies)
            if ht.status_code == 200:
                for m2 in re.finditer(r'<a href="([^"]+\.torrent)"', ht.text):
                    tor_path = m2.group(1)
                    tor_url = tor_path if tor_path.startswith('http') else tor_base.rstrip('/') + '/' + tor_path
                    tor_name = tor_path.split('/')[-1] if '/' in tor_path else tor_path
                    log(f'[OnlineFix] Torrent: {tor_name}')
                    indicator('Online-Fix torrent...', 'working')
                    rt = sess.get(tor_url, timeout=120, headers=headers, cookies=cookies)
                    if rt.status_code != 200: break
                    tor_path_out = out_dir / tor_name
                    with open(str(tor_path_out), 'wb') as f: f.write(rt.content)
                    log(f'[OnlineFix] Torrent kaydedildi: {tor_path_out}')
                    indicator('OnlineFix torrent hazır', 'online')
                    os.startfile(str(out_dir))
                    return True
        return False
    
    def open_onlinefix_auto(self, result):
        game_name = str(result.get('name', '') or '')
        appid = str(result.get('appid', ''))
        if not game_name:
            self._set_indicator('Oyun adi yok', 'offline')
            return
        def _task():
            import re as _re, urllib.parse as _up, webbrowser as _wb
            sess = requests.Session()
            sess.headers.update({'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'})
            game_url = None
            try:
                self._set_indicator('Online-Fix aranıyor...', 'working')
                # Search by appid first
                if appid:
                    r = sess.get(f'https://online-fix.me/index.php?do=search&subaction=search&story={appid}', timeout=15)
                    for m in _re.finditer(r'href="(https://online-fix\.me/games/[^"]+\.html)"', r.text):
                        c = m.group(1).split('#')[0]
                        if c: game_url = c; break
                # Search by name
                if not game_url:
                    q = _up.quote(game_name[:80].strip())
                    r = sess.get(f'https://online-fix.me/index.php?do=search&subaction=search&story={q}', timeout=15)
                    candidates = []
                    seen = set()
                    for m in _re.finditer(r'href="(https://online-fix\.me/games/[^"]+\.html)"', r.text):
                        u = m.group(1).split('#')[0]
                        if u not in seen: seen.add(u); candidates.append(u)
                    sw = set(_re.findall(r'[a-z0-9]+', game_name.lower()))
                    best_score = 0
                    for c in candidates:
                        slug = c.split('/')[-1].replace('.html','').replace('-po-seti','').replace('-',' ').lower()
                        words = set(_re.findall(r'[a-z0-9]+', slug))
                        score = len(sw & words)
                        if score > best_score: best_score = score; game_url = c
                if not game_url:
                    self.log('[OnlineFix] online-fix.me\'de bulunamadı')
                    self._set_indicator('OnlineFix: bulunamadı', 'offline')
                    return
                self.log(f'[OnlineFix] Sayfa: {game_url}')
                # Fetch page for download links
                r = sess.get(game_url, timeout=15)
                phpsessid = sess.cookies.get('PHPSESSID', '')
                # Extract structured URLs
                dl_urls = set()
                for m in _re.finditer(r'(https?://(?:uploads|hosters|drive|torrents)\.online-fix\.me:\d+/[^"\']+)', r.text):
                    dl_urls.add(m.group(1).rstrip('/'))
                for m in _re.finditer(r'(https?://uploads\.online-fix\.me:\d+/(?:uploads|torrents)/[^"\']+)', r.text):
                    dl_urls.add(m.group(1).rstrip('/'))
                # Setup output dir
                _sv = self.settings.get('save_path', '') or ''
                _of_root = Path(_sv, 'Online Fixes') if _sv and Path(_sv).exists() else Path(_os.environ['TEMP'], 'SteamToolsLua', 'OnlineFix')
                _of_root.mkdir(parents=True, exist_ok=True)
                _safe_name = _re.sub(r'[\\/:*?"<>|]', '_', game_name.strip())[:80]
                _out_dir = _of_root / _safe_name
                _out_dir.mkdir(parents=True, exist_ok=True)
                _of_headers = {'User-Agent': 'Mozilla/5.0', 'Referer': 'https://online-fix.me/'}
                _of_cookies = {'PHPSESSID': phpsessid}
                # Try structured download
                dl_attempted = False
                if dl_urls:
                    dl_attempted = True
                    _downloaded = _download_structured(sess, dl_urls, _out_dir, appid, _of_headers, _of_cookies, _find_steam_game_path,
                        lambda m: self.log(m), lambda t,s: self._set_indicator(t,s))
                    if _downloaded:
                        _save_dl_name(game_name)
                        return
                # Only open browser if ZIP download was attempted but failed
                if dl_attempted:
                    self.log('[OnlineFix] Yapısal indirme başarısız, tarayıcı açılıyor')
                    self._set_indicator('OnlineFix: tarayıcı açıldı', 'online')
                    _wb.open(game_url)
                else:
                    self.log('[OnlineFix] Yapısal link yok')
                    self._set_indicator('OnlineFix: link yok', 'offline')
                _save_dl_name(game_name)
            except Exception as ex:
                self.log(f'[OnlineFix] Hata: {ex}')
                self._set_indicator('Online-Fix: hata', 'offline')
        threading.Thread(target=_task, daemon=True).start()
    SteamApp.open_onlinefix = open_onlinefix_auto
    SteamApp.open_result_steamdb = open_onlinefix_auto



    # ---- Unlock All (batch unlock from ZIPs in used/) ----
    def _flatten_stplug_lua(appid, log_func=None):
        stplug_dir = Path("C:\\Program Files (x86)\\Steam\\config\\stplug-in")
        expected = stplug_dir / f"{appid}.lua"
        if not expected.exists():
            candidates = list(stplug_dir.rglob(f"{appid}.lua"))
            if candidates:
                _shutil.copy2(str(candidates[0]), str(expected))
                if log_func:
                    log_func(f'[Flatten] {appid}.lua alt klasörden kopyalandı: {candidates[0].parent.name}/')

    def _download_manifest_sync(appid, log_func=None):
        try:
            if log_func: log_func(f'[Manifest] AppID {appid} flatten lua check...')
            _flatten_stplug_lua(appid, log_func=log_func)
            if log_func: log_func(f'[Manifest] AppID {appid} powershell başlatılıyor...')
            raw = _b64.b64decode(_MANIFESTS_PS1_B64)
            script = raw.decode('utf-16-le')
            tmp = _tempfile.NamedTemporaryFile(mode='w', suffix='.ps1', delete=False, encoding='utf-8')
            tmp.write(script)
            tmp.close()
            env = os.environ.copy()
            env['APP_ID'] = appid
            env['MANIFEST_MODE'] = 'github'
            env['MANIFEST_SINGLE_RUN'] = '1'
            env['MANIFEST_NO_PROMPT'] = '1'
            si = _subprocess.STARTUPINFO()
            si.dwFlags |= _subprocess.STARTF_USESHOWWINDOW
            if log_func: log_func(f'[Manifest] AppID {appid} powershell çalıştırılıyor (180sn timeout)...')
            result = _subprocess.run(
                ["powershell", "-ExecutionPolicy", "Bypass", "-File", tmp.name],
                capture_output=True, text=True, timeout=180,
                startupinfo=si, creationflags=0x08000000, env=env
            )
            if log_func:
                log_func(f'[Manifest] AppID {appid} returncode={result.returncode}')
                if result.stdout.strip():
                    for line in result.stdout.strip().splitlines()[:10]:
                        log_func(f'[Manifest] stdout: {line[:200]}')
                if result.stderr.strip():
                    log_func(f'[Manifest] stderr: {result.stderr.strip()[:300]}')
            return result.returncode == 0
        except _subprocess.TimeoutExpired:
            if log_func: log_func(f'[Manifest] AppID {appid} timeout (180sn aşıldı)')
            return False
        except Exception as e:
            if log_func: log_func(f'[Manifest] AppID {appid} error: {e}')
            return False
        finally:
            try:
                if tmp and os.path.exists(tmp.name): os.unlink(tmp.name)
            except: pass

